//h4[contains(@class, 'text-sm') and contains(@class, 'text-gray-500')]/text()@js:
// 步骤1：兼容输入，统一转为数组（核心：按索引访问，不用任何方法）
var originArr = [];
if (Object.prototype.toString.call(result) === "[object Array]") {
    originArr = result;
} else {
    originArr = [result || ""]; // 非数组强制转为数组
}

// 步骤2：取出原始分类项（按索引取第1个元素，不用任何方法）
var originTag = originArr[0] || "";

// 步骤3：手动清理前后空格（纯索引+字符串累加，不用charAt/substring）
var cleanTag = "";
var startIdx = 0;
var endIdx = 0;
var tagLen = 0;

// 第一步：计算“字符串”长度（遍历到undefined为止，不用length属性）
while (originTag[tagLen] !== undefined) {
    tagLen++;
}

// 第二步：找到开头非空格的索引
while (startIdx < tagLen) {
    var sChar = originTag[startIdx];
    if (sChar !== " " && sChar !== "\t" && sChar !== "\n") {
        break;
    }
    startIdx++;
}

// 第三步：找到结尾非空格的索引
endIdx = tagLen - 1;
while (endIdx >= startIdx) {
    var eChar = originTag[endIdx];
    if (eChar !== " " && eChar !== "\t" && eChar !== "\n") {
        break;
    }
    endIdx--;
}

// 第四步：累加有效字符（纯索引+字符串拼接）
if (startIdx <= endIdx) {
    for (var i = startIdx; i <= endIdx; i++) {
        cleanTag += originTag[i];
    }
}

// 步骤4：将空格分隔转为逗号分隔（纯索引+累加，不用split/replace）
var commaTag = "";
var cleanLen = 0;
// 计算cleanTag长度
while (cleanTag[cleanLen] !== undefined) {
    cleanLen++;
}
// 遍历替换空格为逗号
for (var j = 0; j < cleanLen; j++) {
    var cChar = cleanTag[j];
    if (cChar === " ") {
        commaTag += ","; // 空格换成逗号
    } else {
        commaTag += cChar; // 其他字符直接累加
    }
}

// 步骤5：拼接K漫画前缀
var finalTag = "K漫";
if (commaTag !== "") {
    finalTag += "," + commaTag;
}

// 步骤6：返回数组格式（与原输入结构一致）
[finalTag];

